var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저... 전부 처치한 거죠?","JPN":"ぜ……全部倒したんですよね？","ENG":"W-we took care of them all, right?","TWN":"加上這個……全部解決掉了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"예정에 없던 갑작스런 싸움이었지만 시청자 여러분의 후원으로 어떻게든 이겨낸 것 같아요.","JPN":"予定になかった戦闘でしたが、視聴者の皆様のおかげで頑張れました。","ENG":"That was unexpected, but thanks to you viewers, we managed to overcome it.","TWN":"雖然是場突如其來的戰鬥，但在各位觀眾的支援下總算是贏了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"1부 방송은 여기서 마치고 잠시 쉬어가도록 할게요.","JPN":"それでは、第1部はこれで終了とさせていただきます。","ENG":"This concludes the first part of our show. We'll see you after the break.","TWN":"頒布消息：廣播的第一部分就到此為止，稍微休息一下吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"지금까지 여러분의 스윗 큐트 프리티 카운터 아이돌 미야와......","JPN":"皆さんの、スウィート・キュート・プリティー、カウンターアイドルのミヤと……","ENG":"This is your sweet ♬ cute ♥ pretty ★ Counter and singer, Miya, and...","TWN":"我是大家甜蜜可愛又美麗的制裁者偶像米婭~"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"...가은이었습니다.","JPN":"……ユキでした。","ENG":"Gaeun.","TWN":"我是嘉恩。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"침식체 반응...... 완전소실.","JPN":"侵食体反応……完全消失。","ENG":"No more C.O. responses.","TWN":"侵蝕體反應……完全消失。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"훌륭한 전투였다, 제군들.","JPN":"見事な戦闘だったぞ、諸君。","ENG":"Good job, soldiers.","TWN":"終於，真是場精彩的戰鬥，各位。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"괜찮으세요, 제복 언니들?","JPN":"制服のお姉さんたち、大丈夫ですか？","ENG":"Are you okay, ladies in uniform?","TWN":"制服姐姐們，沒事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"덕분에 살았어.","JPN":"おかげで助かったよ。","ENG":"Thank you.","TWN":"資料都還在，多虧了你們，活下來了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리 무모한 소대장 때문에 꼼짝없이 죽는 줄 알았는데.","JPN":"無謀なうちの小隊長のせいで、本当に死にかけたね。","ENG":"We almost died because of our reckless commander.","TWN":"多虧我們爛到渣的小隊長，我還以為要完蛋了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무모하다니! 덕분에 그 솔로카오인지 뭔지를 찾는다고 고생할 일이 줄었잖아?!","JPN":"無謀だと！？\\nその小隊長のおかげで、ソロカオとかいうやつを探す手間が省けただろ？","ENG":"Who are you calling reckless? It was because of me that you didn't have to look for what's-its-name, Solocaos.","TWN":"爛？虧了我，那個什麼找獨株可可的麻煩事不是沒了嘛？！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이게 다 나의 깊은 경험에서 우러난 작전의 일환인 거다.","JPN":"これが幾多の闘いを勝ち抜いてきた、\\n私の経験から生まれた完璧な作戦だぞ。","ENG":"You should thank me and my ability to think ahead.","TWN":"這全是我基於豐富經驗，制定的翻盤大作戰啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"작전 두 번만 했다간 소대에 남아나는 사람이 없겠네.","JPN":"その完璧な作戦で、小隊が全滅しかけたんだけど。","ENG":"We'd all die if we thanked you twice.","TWN":"這作戰要是再進行一次，芬里爾小隊就要沒人了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"하긴, 이 정도 양이라면 솔로카오를 더 채집할 필요는 없겠네요.","JPN":"まあ、この量ならこれ以上ソロカオを採取する必要はなさそうですね。","ENG":"But she's right. We've got enough Solocaos now.","TWN":"一口氣採了這麼多，已經不用了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"다들 고생했어요.","JPN":"皆さん、お疲れ様でした。","ENG":"Everyone, good job.","TWN":"大家辛苦啦。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"자, 그럼 이제 모은 것들을 손질할 차례인데......","JPN":"それじゃあ、集めたソロカオの処理をする番ですが……","ENG":"Now, it's time we prepare what we've got...","TWN":"好，那就該處理採集到的東西了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"가, 가은아? 왜 날 보면서 그런 말을 하는 거야?","JPN":"ユ、ユキちゃん？　何でミヤの方を見るの……？","ENG":"G-Gaeun, why are you looking at me as you say that?","TWN":"嘉、嘉恩？為什麼看著我說這種話啊？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그야 대본에 따르면......","JPN":"もちろん台本通りに……","ENG":"Well, according to our script...","TWN":"按照臺本的話……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"모, 못해! 난 그런 거 못한다고!!","JPN":"む、無理！　ミヤには、絶対に無理！！","ENG":"N-no! I'm not going to do that!","TWN":"不、不行！都說了做不到！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아, 아, 마이크 테스트.","JPN":"あー、あー。マイクテスト。","ENG":"Ah, ah. Mic test.","TWN":"啊，啊，麥克風測試。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"솔로카오 채집 작전에 참여하신 여러분들은 집중해주시기 바랍니다.","JPN":"ソロカオ採取作戦に参加している皆様、よろしいでしょうか。","ENG":"Attention everyone on the Solocao-harvesting mission.","TWN":"希望參與可可採集作戰的各位集中一下。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자! 임무와 관련한 중대 사항을 전달해 드리겠습니다!","JPN":"それでは、任務に関する重大事項をお伝えします！","ENG":"I've got an important announcement related to your mission.","TWN":"好的！接下來向各位轉達一些與任務有關的重要事項！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};